module div_8bit (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output wire [15:0] result
);

reg res_valid_reg;
reg start_cnt;
reg [3:0] cnt;
reg [8:0] neg_divisor;
reg [7:0] dividend_abs;
reg [7:0] divisor_abs;
reg [15:0] result_reg;
reg [17:0] SR;
always_comb begin
    if(rst == 1'b1)begin
        res_valid = 1'b0;
    end else if(cnt[3] == 1'b1 && cnt != 4'd8)begin
        res_valid = 1'b0;
    end else if(res_valid == 1'b1 && res_ready == 1'b1)begin
        res_valid = 1'b0;
    end else begin
        res_valid = res_valid_reg;
    end
end
always @(posedge clk) begin
    if(opn_valid == 1'b1 && res_valid == 1'b0)begin
        dividend_abs <= (sign == 1'b1)? ((dividend[7] == 1'b1)? (~dividend + 1'b1): dividend): dividend;
        divisor_abs <= (sign == 1'b1)? ((divisor[7] == 1'b1)? (~divisor + 1'b1): divisor): divisor;
        SR <= {dividend_abs, 1'b0};
        neg_divisor <= (sign == 1'b1)? ~{divisor_abs, 1'b0}+1'b1 : ~{divisor_abs, 1'b0};
        cnt <= 4'd1;
        start_cnt <= 1'b1;
    end else if(start_cnt == 1'b1)begin
        if(cnt[3] == 1'b1)begin
            cnt <= 4'd0;
            start_cnt <= 1'b0;
            SR <= {SR[16:9], 1'b0};
            result_reg <= (sign == 1'b1)? (((dividend[7] ^ divisor[7]) == 1'b1)? (~SR[16:9]+1'b1): SR[16:9]): SR[16:9];
        end else begin
            cnt <= cnt + 1'b1;
            SR <= {SR[16:9], 1'b0};
            case(SR[8])
                1'b0: SR[8:0] <= SR[8:0] + neg_divisor;
                default: SR[8:0] <= SR[8:0];
            endcase
        end
    end
end
always @(posedge clk) begin
    if(rst == 1'b1)begin
        res_valid_reg <= 1'b0;
    end else if(cnt[3] == 1'b1 && cnt != 4'd8)begin
        res_valid_reg <= 1'b1;
    end else if(res_valid == 1'b1 && res_ready == 1'b1)begin
        res_valid_reg <= 1'b0;
    end
end
assign result = result_reg;
endmodule
